const items = $input.all();
const sd = $getWorkflowStaticData('global');
sd.lastSeenExec = sd.lastSeenExec || {};

const heartbeats = [];

for (const item of items) {
  const data = (item.json && item.json.data) || [];
  if (!Array.isArray(data)) continue;
  for (const e of data) {
    const wfId = e.workflowId;
    const persona = AGENT_MAP[wfId];
    if (!persona) continue;
    const execId = String(e.id);
    const lastSeen = String(sd.lastSeenExec[wfId] || '0');
    if (Number(execId) <= Number(lastSeen)) continue;

    // Lightweight classification — status only, no runData required
    let outcome, summary;
    if (e.status === 'error' || e.status === 'crashed') {
      outcome = 'error';
      summary = persona.name + ' hit an error — Wolf may be alerting.';
    } else if (e.status === 'success') {
      outcome = 'ran_clean';
      // Generic "agent ran" — we don't know if it produced artifact without runData
      // The dashboard's ticket count tells the artifact story; heartbeats just confirm "alive"
      summary = persona.name + ' ran a check.';
    } else {
      outcome = 'unknown';
      summary = persona.name + ' (' + e.status + ')';
    }

    heartbeats.push({
      agentId: persona.id,
      agentName: persona.name,
      action: 'fired',
      summary,
      outcome,
      workflow_id: wfId,
      exec_id: execId,
      at_iso: e.startedAt
    });

    if (Number(execId) > Number(sd.lastSeenExec[wfId] || 0)) {
      sd.lastSeenExec[wfId] = execId;
    }
  }
}

return heartbeats.map(hb => ({json: hb}));

